#wrapper {
  max-width: 900px;
  margin: 35px auto;
  padding: 24px;
  background: #fff;
  border: 1px solid #e0e0e0;
  border-radius: 8px;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.07);
}

h2 {
  font-family: sans-serif;
  font-size: 18px;
  font-weight: 600;
  color: #333;
  margin: 32px 0 4px;
}

h2:first-child {
  margin-top: 0;
}

p.desc {
  font-family: sans-serif;
  font-size: 13px;
  color: #777;
  margin: 0 0 12px;
}

.grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}

.card {
  border: 1px solid #eee;
  border-radius: 6px;
  padding: 12px;
}

.card h3 {
  font-family: sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: #444;
  margin: 0 0 2px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.card p {
  font-family: sans-serif;
  font-size: 12px;
  color: #999;
  margin: 0 0 8px;
}
